import React from 'react';
import './skills.css';
import { motion } from 'framer-motion';
import { FaHtml5, FaCss3Alt, FaJs, FaReact, FaPython, FaCuttlefish } from 'react-icons/fa';

const skills = [
  { icon: <FaHtml5 />, name: "HTML", level: 85 },
  { icon: <FaCss3Alt />, name: "CSS", level: 75 },
  { icon: <FaJs />, name: "JavaScript", level: 70 },
  { icon: <FaReact />, name: "React JS", level: 75 },
  { icon: <FaCuttlefish />, name: "C / C++", level: 65 },
  { icon: <FaPython />, name: "Python", level: 80 }
];

const Skills = () => {
  return (
    <div className="skills-modern">
      <h2 className="skills-title">Skills</h2>
      <div className="skills-grid">
        {skills.map((skill, i) => (
          <motion.div 
            key={i} 
            className="skill-box"
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.1, duration: 0.4 }}
            viewport={{ once: true }}
          >
            <div className="skill-header">
              <span className="icon">{skill.icon}</span>
              <span className="name">{skill.name}</span>
            </div>
            <div className="progress-bar">
              <div className="progress-fill" style={{ width: `${skill.level}%` }}>
                <span>{skill.level}%</span>
              </div>
            </div>
          </motion.div>
        ))}
      </div>
    </div>
  );
};

export default Skills;
